111	/// Run a bash script, return (exit_code, stdout, stderr). Saves traces to case dir.
112	fn rbtdrf_run_bash(
113	    project_root: &Path,
114	    script: &str,
115	    dir: &Path,
116	    trace_prefix: &str,
117	) -> Result<(i32, String, String), String> {
118	    let output = Command::new(rbtdri_bash_program())
119	        .arg("-c")
120	        .arg(script)
121	        .current_dir(project_root)
122	        .output()
123	        .map_err(|e| format!("bash execution failed: {}", e))?;
124	
125	    let stdout = String::from_utf8_lossy(&output.stdout).into_owned();
126	    let stderr = String::from_utf8_lossy(&output.stderr).into_owned();
127	    let code = output.status.code().unwrap_or(-1);
128	
129	    let _ = std::fs::write(dir.join(format!("{}-script.sh", trace_prefix)), script);
130	    let _ = std::fs::write(dir.join(format!("{}-stdout.txt", trace_prefix)), &stdout);
131	    let _ = std::fs::write(dir.join(format!("{}-stderr.txt", trace_prefix)), &stderr);
132	
133	    Ok((code, stdout, stderr))
134	}
