1537	        Ok(r) => r,
1538	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
1539	    };
1540	    let keys_file = dir.join(format!("{}-keys.txt", label));
1541	    let body_file = dir.join(format!("{}-body.sh", label));
1542	    if let Err(e) = std::fs::write(&keys_file, keys) {
1543	        return rbtdre_Verdict::Fail(format!("{}: write keys failed: {}", label, e));
1544	    }
1545	    if let Err(e) = std::fs::write(&body_file, body) {
1546	        return rbtdre_Verdict::Fail(format!("{}: write body failed: {}", label, e));
1547	    }
1548	    let buv = root.join(RBTDRF_BUV_VALIDATION);
1549	    let spine = root.join(RBTDRF_RBLDS_SPINE);
1550	    let script = format!(
1551	        "set -euo pipefail\n\
1552	         source '{}'\n\
1553	         source '{}'\n\
1554	         zbuv_kindle\n\
1555	         zrbld_spine_validate '{}' '{}'",
1556	        rbtdrx_native_to_posix(&buv),
