1464	    };
1465	    let buc = root.join(RBTDRF_BUC_COMMAND);
1466	
1467	    let assertion = match expect {
1468	        Some(out) => format!("test \"$(buc_native_path_capture '{}')\" = '{}'", input, out),
1469	        None => format!("buc_native_path_capture '{}'", input),
1470	    };
1471	    let script = format!(
1472	        "set -euo pipefail\nsource '{}'\nexport BURD_OSTYPE='{}'\n{}",
1473	        rbtdrx_native_to_posix(&buc),
1474	        ostype,
1475	        assertion,
1476	    );
